TriggerOraclev10g.body:
DECLARE
	v_user VARCHAR2(150);
	v_now  TIMESTAMP := CURRENT_TIMESTAMP;
BEGIN
    v_user := COALESCE(
                 SYS_CONTEXT('APEX$SESSION', 'APP_USER'),
                 USER
              );

    IF INSERTING THEN
        :NEW.created_by := v_user;
        :NEW.created_on := v_now;
    END IF;

   IF UPDATING THEN
        :NEW.updated_by := v_user;
        :NEW.changed_on := v_now;
    END IF;

END;
